        "is_production_order",
        "delivery_method",
        "receiving_operation_faci",
      ]);
      this.triggerEvent("func_reset_delivery_method");
    }
  }

  if (movementType) {
    await configureFields(movementType, this.getValue("is_production_order"));
    await configureButtons(
      movementType,
      pageStatus,
      data.stock_movement_status
    );

