  this.hide(CONFIG.hideFields[pageStatus]);

  if (pageStatus !== "Add" && movementType && balanceIndex.length > 0) {
    setTimeout(() => {
      this.setData({ balance_index: balanceIndex });
    }, 2000);
  }
})();

