    receivingLocationId,
    qtyChangeValue,
    balance,
    allData,
    subformData,
    movementType,
    organizationId,
  ) {
    if (!receivingLocationId) {
      throw new Error(
        "Receiving location ID is required for Location Transfer",
      );
