            batch_id: null,
            bin_location: item.location_id,
            item_uom: item.quantity_uom,
            line_no: index + 1,
            reserved_qty: item.total_quantity,
            delivered_qty: 0,
            open_qty: item.total_quantity,
            reserved_date: new Date()
              .toISOString()
              .slice(0, 19)
